<?phpnamespace App\Controller;use App\Entity\Authority;use App\Entity\KohUtilisateur;use App\Entity\SysAdminOperation;use App\Form\KohUtilisateurType;use App\Repository\AuthorityRepository;use App\Repository\KohUtilisateurRepository;use App\Repository\SysAdminOperationRepository;use DateTime;use DateTimeZone;use Doctrine\ORM\EntityManagerInterface;use Exception;use Knp\Component\Pager\PaginatorInterface;use Sensio\Bundle\FrameworkExtraBundle\Configuration\Security;use Swift_Attachment;use Swift_Image;use Swift_Mailer;use Swift_Message;use Symfony\Bundle\FrameworkBundle\Controller\AbstractController;use Symfony\Component\HttpFoundation\File\UploadedFile;use Symfony\Component\HttpFoundation\RedirectResponse;use Symfony\Component\HttpFoundation\Request;use Symfony\Component\HttpFoundation\Response;use Symfony\Component\Routing\Annotation\Route;use Symfony\Component\Security\Core\Encoder\UserPasswordEncoderInterface;/** * @Security("is_granted('ROLE_SUPER_ADMIN')") * Class KohUtilisateurController * @package App\Controller */class KohUtilisateurController extends AbstractController{    /**     * @Security("user.getIsActived() and user.getIsKohUser() and user.getIsConfirmed()")     * @Route("/super-admin/utilisateurs", name="koh_utilisateur_index", methods={"GET"})     * @param KohUtilisateurRepository $kohUtilisateurRepository     * @param PaginatorInterface $paginator     * @param Request $request     * @return Response     */    public function index(KohUtilisateurRepository $kohUtilisateurRepository, PaginatorInterface $paginator, Request $request): Response    {        return $this->render('koh_utilisateur/index.html.twig', [            'koh_utilisateurs' => $paginator->paginate($kohUtilisateurRepository->allKohUtilisateurQuery(), $request->query->getInt('page', 1), 200)        ]);    }    /**     * @Security("user.getIsActived() and user.getIsKohUser() and user.getIsConfirmed() and user.getIsAdmin()")     * @Route("/super-admin/utilisateurs/new", name="koh_utilisateur_new", methods={"GET","POST"})     * @param Request $request     * @param UserPasswordEncoderInterface $encoder     * @param Swift_Mailer $mailer     * @param AuthorityRepository $authorityRepository     * @return Response     * @throws Exception     */    public function new(Request $request, UserPasswordEncoderInterface $encoder, Swift_Mailer $mailer, AuthorityRepository $authorityRepository): Response    {        $kohUtilisateur = new KohUtilisateur();        $form = $this->createForm(KohUtilisateurType::class, $kohUtilisateur);        $form->handleRequest($request);        if ($form->isSubmitted() && $form->isValid()) {            $entityManager = $this->getDoctrine()->getManager();            $entityManager->persist($kohUtilisateur);            $kohUtilisateur->setIsKohUser(true);            $random = $this->generate_string(100);            $kohUtilisateur->setConfirmationToken($random);            $kohUtilisateur->setIsConfirmed(false);            $kohUtilisateur->setIsActived(false);            if ($request->get('isAdmin')) {                $kohUtilisateur->setIsAdmin(true);            } else {                $kohUtilisateur->setIsAdmin(false);            }            $date = new DateTime('now', new DateTimeZone('GMT'));            $time = $date->getTimestamp() + (24 * 60 * 60);            $kohUtilisateur->setTokenValidity($time);            $kohUtilisateur->setCreatedAt(new DateTime('now', new DateTimeZone('GMT')));            $role = $authorityRepository->findOneBy(['name' => 'SUPER_ADMIN']);            if ($role === null) {                $role = new Authority();                $role->setName('SUPER_ADMIN')                    ->setIsRoleKoh(true)                    ->setDescription('Rôle des administrateur de mbeyan');                $entityManager->persist($role);                $entityManager->flush();            }            $kohUtilisateur->addAuthority($role);            $kohUtilisateur->setPassword($encoder->encodePassword($kohUtilisateur, $kohUtilisateur->getPassword()));            $entityManager->flush();            $message = (new Swift_Message("création de compte"))                ->setFrom('contact@mbeyan.com')                ->setTo($kohUtilisateur->getEmail());            $img = $message->embed(Swift_Image::fromPath('images/koh-logo.png'));            $message                ->setBody($this->renderView(                    'mailer/registration_admin.html.twig',                    [                        'firstName' => $kohUtilisateur->getFirstName(),                        'lastName' => $kohUtilisateur->getLastName(),                        'random' => $random,                        'img' => $img                    ]                ),                    'text/html');            $mailer->send($message);            $this->addFlash('success', 'Utilisateur koh enregistré');            $sysOp = new SysAdminOperation();            $sysOp->setCreatedAt(new DateTime('now', new DateTimeZone('GMT')))                ->setUpdatedAt(new DateTime('now', new DateTimeZone('GMT')))                ->setKohUtilisateur($this->getUser())                ->setDescription('Enregistrement de compte utilisateur KOH')                ->setUserAffected($kohUtilisateur->getFirstName() . ' ' . $kohUtilisateur->getLastName());            $entityManager->persist($sysOp);            $entityManager->flush();            return $this->redirectToRoute('koh_utilisateur_index');        }        return $this->render('koh_utilisateur/new.html.twig', [            'koh_utilisateur' => $kohUtilisateur,            'form' => $form->createView(),        ]);    }    /**     * @Security("user.getIsActived() and user.getIsKohUser() and user.getIsConfirmed()")     * @Route("/super-admin/utilisateurs/{id}", name="koh_utilisateur_show", methods={"GET"})     * @param KohUtilisateur $kohUtilisateur     * @return Response     */    public function show(KohUtilisateur $kohUtilisateur): Response    {        return $this->render('koh_utilisateur/show.html.twig', [            'koh_utilisateur' => $kohUtilisateur,        ]);    }    /**     * @Security("user.getIsActived() and user.getIsKohUser() and user.getIsConfirmed()")     * @Route("/super-admin/utilisateurs/{id}/edit", name="koh_utilisateur_edit", methods={"GET","POST"})     * @param Request $request     * @param KohUtilisateur $kohUtilisateur     * @param UserPasswordEncoderInterface $encoder     * @return Response     * @throws Exception     */    public function edit(Request $request, KohUtilisateur $kohUtilisateur, UserPasswordEncoderInterface $encoder): Response    {        $form = $this->createForm(KohUtilisateurType::class, $kohUtilisateur);        $form->handleRequest($request);        if ($form->isSubmitted() && $form->isValid()) {            $kohUtilisateur->setPassword($encoder->encodePassword($kohUtilisateur, $kohUtilisateur->getPassword()));            $this->getDoctrine()->getManager()->flush();            $this->addFlash('success', 'Compte utilisateur modifié');            $sysOp = new SysAdminOperation();            $sysOp->setCreatedAt(new DateTime('now', new DateTimeZone('GMT')))                ->setUpdatedAt(new DateTime('now', new DateTimeZone('GMT')))                ->setKohUtilisateur($this->getUser())                ->setDescription('Modification de son compte utilisateur KOH');            $this->getDoctrine()->getManager()->persist($sysOp);            $this->getDoctrine()->getManager()->flush();            return $this->redirectToRoute('koh_utilisateur_index');        }        if ($this->getUser()->getId() === $kohUtilisateur->getId()) {            return $this->render('koh_utilisateur/edit.html.twig', [                'koh_utilisateur' => $kohUtilisateur,                'form' => $form->createView(),            ]);        }        $this->addFlash('danger', 'Vous ne pouvez pas modifier ce compte');        return $this->redirectToRoute('koh_utilisateur_index');    }    /**     * @Security("user.getIsActived() and user.getIsKohUser() and user.getIsConfirmed() and user.getIsAdmin()")     * @Route("/super-admin/utilisateurs/{id}", name="koh_utilisateur_delete", methods={"DELETE"})     * @param Request $request     * @param KohUtilisateur $kohUtilisateur     * @return Response     * @throws Exception     */    public function delete(Request $request, KohUtilisateur $kohUtilisateur): Response    {        if ($this->getUser()->getId() === $kohUtilisateur->getId()) {            $this->addFlash('danger', 'Vous ne pouvez pas supprimer votre compte');            return $this->redirectToRoute('koh_utilisateur_index');        }        if ($this->isCsrfTokenValid('delete' . $kohUtilisateur->getId(), $request->request->get('_token'))) {            $entityManager = $this->getDoctrine()->getManager();            // VERIFICATION KOH USER            if ($kohUtilisateur->getIsKohUser()) {                // SUPPRESSION DES EXPERTISES FAITES PAR CE UTILISATEUR                foreach ($kohUtilisateur->getExpertises() as $expertise) {                    $expertise->setCreatedBy(null);                    $entityManager->flush();                }            }            if (!$kohUtilisateur->getIsKohUser() && $kohUtilisateur->getTypeCompte() != null && $kohUtilisateur->getIsAdmin()) {                foreach ($kohUtilisateur->getBienClients() as $bienClient) {                    foreach ($bienClient->getExpertises() as $expertise) {                        $entityManager->remove($expertise);                        $entityManager->flush();                    }                    $entityManager->remove($bienClient);                    $entityManager->flush();                }            }            $entityManager->remove($kohUtilisateur);            $entityManager->flush();            $this->addFlash('success', 'L\'utilisateur a été supprimé');            $sysOp = new SysAdminOperation();            $sysOp->setCreatedAt(new DateTime('now', new DateTimeZone('GMT')))                ->setUpdatedAt(new DateTime('now', new DateTimeZone('GMT')))                ->setKohUtilisateur($this->getUser())                ->setDescription('Suppresion de compte utilisateur KOH')->setUserAffected($kohUtilisateur->getFirstName() . ' ' . $kohUtilisateur->getLastName());            $entityManager->persist($sysOp);            $entityManager->flush();        }        return $this->redirectToRoute('koh_utilisateur_index');    }    /**     * @Route("/confirmation-admin-account", methods={"GET"})     * @param Request $request     * @param KohUtilisateurRepository $kohUtilisateurRepository     * @return RedirectResponse     * @throws Exception     */    public function confirmationAdminAccount(Request $request, KohUtilisateurRepository $kohUtilisateurRepository): ?RedirectResponse    {        $token = $request->get('compte_remember_token');        $kohUtilisateur = $kohUtilisateurRepository->findOneBy(['confirmationToken' => $token]);        if ($kohUtilisateur !== null) {            $date = new DateTime('now', new DateTimeZone('GMT'));            $time = $date->getTimestamp();            if ($time > $kohUtilisateur->getTokenValidity()) {                $this->addFlash('danger', 'Le delai de confirmation est depassé');                return $this->redirectToRoute('app_login');            }            $kohUtilisateur->setIsConfirmed(true)                ->setConfirmationToken(null);            $kohUtilisateur->setConfirmationToken(null);            $kohUtilisateur->setTokenValidity(null);            $this->getDoctrine()->getManager()->flush();            $this->addFlash('success', 'Votre compte a été confirmé avec succès');            $sysOp = new SysAdminOperation();            $sysOp->setCreatedAt(new DateTime('now', new DateTimeZone('GMT')))                ->setUpdatedAt(new DateTime('now', new DateTimeZone('GMT')))                ->setKohUtilisateur($this->getUser())                ->setDescription('Confirmation de compte son utilisateur KOH');            $this->getDoctrine()->getManager()->persist($sysOp);            $this->getDoctrine()->getManager()->flush();            return $this->redirectToRoute('app_login');        }        return $this->redirectToRoute('app_login');    }    /**     * @Security("user.getIsActived() and user.getIsKohUser() and user.getIsConfirmed() and user.getIsAdmin()")     * @Route("/super-admin/utilisateurs/{id}/activation-account", name="koh_utilisateur_activation_account", methods={"GET"})     * @param KohUtilisateur $kohUtilisateur     * @return RedirectResponse     * @throws Exception     */    public function activationAccount(KohUtilisateur $kohUtilisateur): ?RedirectResponse    {        $kohUtilisateur->setIsActived(true);        $kohUtilisateur->setUpdatedAt(new DateTime('now', new DateTimeZone('GMT')));        $this->getDoctrine()->getManager()->flush();        $this->addFlash('success', 'Le compte a été activé');        $sysOp = new SysAdminOperation();        $sysOp->setCreatedAt(new DateTime('now', new DateTimeZone('GMT')))            ->setUpdatedAt(new DateTime('now', new DateTimeZone('GMT')))            ->setKohUtilisateur($this->getUser())            ->setDescription('Activation de compte utilisateur KOH')->setUserAffected($kohUtilisateur->getLastName() . ' ' . $kohUtilisateur->getFirstName());        $this->getDoctrine()->getManager()->persist($sysOp);        $this->getDoctrine()->getManager()->flush();        return $this->redirectToRoute('koh_utilisateur_index');    }    /**     * @Security("user.getIsActived() and user.getIsKohUser() and user.getIsConfirmed() and user.getIsAdmin()")     * @Route("/super-admin/utilisateurs/{id}/desactivation-account", name="koh_utilisateur_desactivation_account", methods={"GET"})     * @param KohUtilisateur $kohUtilisateur     * @return RedirectResponse     * @throws Exception     */    public function desactivationAccount(KohUtilisateur $kohUtilisateur): ?RedirectResponse    {        if ($this->getUser()->getId() === $kohUtilisateur->getId()) {            $this->addFlash('danger', 'Vous ne pouvez pas désactiver votre compte');            return $this->redirectToRoute('koh_utilisateur_index');        }        $kohUtilisateur->setIsActived(false);        $this->getDoctrine()->getManager()->flush();        $this->addFlash('success', 'Le compte a été desactivé');        $sysOp = new SysAdminOperation();        $sysOp->setCreatedAt(new DateTime('now', new DateTimeZone('GMT')))            ->setUpdatedAt(new DateTime('now', new DateTimeZone('GMT')))            ->setKohUtilisateur($this->getUser())            ->setDescription('Désactivation de compte utilisateur KOH')->setUserAffected($kohUtilisateur->getLastName() . ' ' . $kohUtilisateur->getFirstName());        $this->getDoctrine()->getManager()->persist($sysOp);        $this->getDoctrine()->getManager()->flush();        return $this->redirectToRoute('koh_utilisateur_index');    }    /**     * @Security("user.getIsActived() and user.getIsKohUser() and user.getIsConfirmed()")     * @Route("/super-admin/utilisateurs/change-user-profile", name="koh_utilisateur_change_user_profile", methods={"POST"})     * @param Request $request     * @param KohUtilisateurRepository $utilisateurRepository     * @return RedirectResponse     * @throws Exception     */    public function changeUserProfile(Request $request, KohUtilisateurRepository $utilisateurRepository): ?RedirectResponse    {        $user = $utilisateurRepository->findOneBy(['username' => $this->getUser()->getUsername()]);        $mimes = "image/gif, image/png, image/jpeg";        // dd($request->files->get('profile_user'));        if (str_contains($mimes, $request->files->get('profile_user')['type'])) {            // $fileF = new UploadedFile($request->files->get('profile_user')['tmp_name'], $request->files->get('profile_user')['name']);            // $user->setUserProfile($request->files->get('profile_user'));            // TODO REPLACE CODE            $file = $request->files->get('profile_user');            // $user->setUserProfile($fileF);            $user->setUserProfile($file);            $this->getDoctrine()->getManager()->flush();            $this->addFlash('success', 'Le profile a été changé avec success');            $sysOp = new SysAdminOperation();            $sysOp->setCreatedAt(new DateTime('now', new DateTimeZone('GMT')))                ->setUpdatedAt(new DateTime('now', new DateTimeZone('GMT')))                ->setKohUtilisateur($this->getUser())                ->setDescription('Changement de profile utilisateur KOH');            $this->getDoctrine()->getManager()->persist($sysOp);            $this->getDoctrine()->getManager()->flush();            return $this->redirectToRoute('koh_utilisateur_show', ['id' => $user->getId()]);        }        $this->addFlash('danger', 'Le type de fichier choisi n\'est pas accepté');        return $this->redirectToRoute('koh_utilisateur_show', ['id' => $user->getId()]);    }    /**     * @Security("user.getIsActived() and user.getIsKohUser() and user.getIsConfirmed() and user.getIsAdmin()")     * @Route("/super-admin/operations", name="koh_utilisateur_operation", methods={"GET"})     * @param SysAdminOperationRepository $sysAdminOperationRepository     * @param PaginatorInterface $paginator     * @param Request $request     * @return Response     */    public function indexSysOperation(SysAdminOperationRepository $sysAdminOperationRepository, PaginatorInterface $paginator, Request $request): Response    {        $operations = $paginator->paginate($sysAdminOperationRepository->getSysOperationQuery(), $request->query->getInt('page', 1), 100);        return $this->render('sys-operation/index.html.twig', [            'operations' => $operations        ]);    }    /**     * @Security("user.getIsActived() and user.getIsKohUser() and user.getIsConfirmed() and user.getIsAdmin()")     * @Route("/super-admin/utilisateurs/resend-client-token/{id}", name="super_admin.utilisateur.resendConfirmation")     * @param KohUtilisateur $kohUtilisateur     * @param Swift_Mailer $mailer     * @return RedirectResponse     * @throws Exception     */    public function resendKohClientToken(KohUtilisateur $kohUtilisateur, Swift_Mailer $mailer): ?RedirectResponse    {        $random = $this->generate_string(100);        $kohUtilisateur->setConfirmationToken($random);        $date = new DateTime('now', new DateTimeZone('GMT'));        $time = $date->getTimestamp() + (24 * 60 * 60);        $kohUtilisateur->setTokenValidity($time);        $kohUtilisateur->setUpdatedAt(new DateTime('now', new DateTimeZone('GMT')));        $this->getDoctrine()->getManager()->flush();        $message = (new Swift_Message("création de compte"))            ->setFrom('contact@mbeyan.com')            ->setTo($kohUtilisateur->getEmail());        $img = $message->embed(Swift_Image::fromPath('images/koh-logo.png'));        $message->setBody($this->renderView(            'mailer/confirmation_token.html.twig',            [                'firstName' => $kohUtilisateur->getFirstName(),                'lastName' => $kohUtilisateur->getLastName(),                'random' => $random,                'img' => $img            ]        ),            'text/html');        $mailer->send($message);        $this->addFlash('success', 'La demande a été envoyé à l\'adresse email de l\'utilisateur.');        $sysOp = new SysAdminOperation();        $sysOp->setCreatedAt(new DateTime('now', new DateTimeZone('GMT')))            ->setUpdatedAt(new DateTime('now', new DateTimeZone('GMT')))            ->setKohUtilisateur($this->getUser())            ->setDescription('Renvoi de token de confirmation de compte utilisateur KOH')->setUserAffected($kohUtilisateur->getLastName() . ' ' . $kohUtilisateur->getFirstName());        $this->getDoctrine()->getManager()->persist($sysOp);        $this->getDoctrine()->getManager()->flush();        return $this->redirectToRoute('koh_utilisateur_index');    }    /**     * @param int $strength     * @return string     * @throws Exception     */    public function generate_string(int $strength = 16): string    {        $permitted_chars = '0123456789abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ';        $input_length = strlen($permitted_chars);        $random_string = '';        for ($i = 0; $i < $strength; $i++) {            $random_character = $permitted_chars[random_int(0, $input_length - 1)];            $random_string .= $random_character;        }        return $random_string;    }    /**     * @Security("user.getIsActived() and user.getIsKohUser() and user.getIsConfirmed() and user.getIsAdmin()")     * @Route("/super-admin/utilisateurs/{id}/change-status", name="koh_utilisateur_change_status")     * @param int $id     * @param EntityManagerInterface $entityManager     * @param KohUtilisateurRepository $kohUtilisateurRepository     * @return RedirectResponse     */    public function changeStatus(int $id, EntityManagerInterface $entityManager, KohUtilisateurRepository $kohUtilisateurRepository): RedirectResponse    {        $kohUtilisateur = $kohUtilisateurRepository->find($id);        if ($kohUtilisateur->getId() == $this->getUser()->getId()) {            $this->addFlash('danger', 'Vous ne pouvez pas changer votre status');            return $this->redirectToRoute('koh_utilisateur_index');        }        if ($kohUtilisateur->getIsAdmin()) {            $kohUtilisateur->setIsAdmin(false);            $entityManager->flush();            $this->addFlash('success', 'Status administrateur retiré à ' . $kohUtilisateur->getEmail());        } else {            $kohUtilisateur->setIsAdmin(true);            $entityManager->flush();            $this->addFlash('success', 'Status administrateur attribué à ' . $kohUtilisateur->getEmail());        }        return $this->redirectToRoute('koh_utilisateur_index');    }}